import React from 'react'
import { useState } from 'react';
import './App.css';
import NAV from '../Nav/nav'
import MAIN from '../Main/Main'
import CREATEWIND from '../CreatePostWindow/CreatePostWindow'
import POSTWINDOW from '../PostWindow/PostWindow'
import Post from '../../Post'
import { openDataBase } from '../db.js'

import {
  BrowserRouter as Router,
  Routes,
  Route,
} from 'react-router-dom';

export default function App() {
  const [listVisible, setListVisible] = useState("")
  // const [count, setCount] = useState(1)
  const [idPost, setIdPost] = useState(0)

  const search = (e) => {
    setListVisible(e)
  }
  const saveData = (e) => {
    Post.push(
      {
        tags: e.tags,
        title: e.title,
        author: e.author,
        img: e.img,
        link: e.link,
        text: e.text,
        id: 14
      },
    )
    console.log(e, "saveData - APP");
  }
  const openWindPots = (id) => {
    setIdPost(id)
    // console.log(id, bool);
  }

  return (
    <div>
      <Router>
        <NAV search={search} />
        <button className="btn dataB">DataBase</button>
        <div className="empty-block"></div>

        <Routes>
          <Route
            exact path="/"
            element={<MAIN listVisible={listVisible} tag={null} list={Post} openWindPots={openWindPots} />}
          />
          <Route
            path="/posts/:id_post"
            // element={<POSTWINDOW listVisible={listVisible} list={Post} listId={Post[idPost]} openWindPots={openWindPots}/>}
            element={<POSTWINDOW list={Post} listId={Post[idPost]} openWindPots={openWindPots} />}
          />
          <Route
            path="/create-post"
            element={<CREATEWIND saveData={saveData} />}
          />
          <Route
            path="*"
            element={<div>ERROR404</div>}
          />

        </Routes>

      </Router>
    </div>
  )
}
